import React from 'react';
// import Sidebar from '../components/Sidebar'; // Dòng này có thể comment hoặc xóa nếu Sidebar được render ở App.js
import '../Dashboard.css';

function Dashboard() {
  return (
    // <div className="dashboard-layout"> // COMMENT HOẶC XÓA DÒNG NÀY nếu App.js đã có div flex bao ngoài
    //   <Sidebar /> // COMMENT HOẶC XÓA DÒNG NÀY nếu Sidebar đã được render ở App.js
      <div className="main-content"> {/* Giữ lại main-content cho nội dung chính của dashboard */}
        {/* Phần Header / Banner với Logo và Tiêu đề */}
        <div className="main-header-banner">
          <img src="/logo_kiemlam.png" alt="Logo Chi cục Kiểm Lâm" className="header-logo" />
          <div className="header-text">
            <h1>CHI CỤC KIỂM LÂM - SỞ NÔNG NGHIỆP VÀ MÔI TRƯỜNG</h1>
            <h2>QUẢN LÝ LÂM SẢN</h2>
          </div>
        </div>

        {/* Nội dung chính của Dashboard */}
        <div className="dashboard-body">
          <p>Chào mừng bạn đến với hệ thống quản lý cơ sở nuôi động vật hoang dã!</p>
          {/* Bạn có thể đặt các thành phần khác của dashboard tại đây */}
          {/* Ví dụ: Các card thông tin, biểu đồ, nút bấm */}
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
            gap: '20px',
            marginTop: '30px'
          }}>
            <div style={{
              backgroundColor: '#f8f9fa',
              padding: '25px',
              borderRadius: 'var(--border-radius)',
              boxShadow: '0 2px 8px var(--shadow-light)',
              textAlign: 'center'
            }}>
              <h3>Tổng số cơ sở</h3>
              <p style={{ fontSize: '2.5em', fontWeight: 'bold', color: 'var(--primary-color)' }}>125</p>
              <p>Cơ sở đang hoạt động</p>
            </div>
            <div style={{
              backgroundColor: '#f8f9fa',
              padding: '25px',
              borderRadius: 'var(--border-radius)',
              boxShadow: '0 2px 8px var(--shadow-light)',
              textAlign: 'center'
            }}>
              <h3>Loài phổ biến</h3>
              <p style={{ fontSize: '1.8em', fontWeight: 'bold', color: 'var(--text-dark)' }}>Rắn hổ mang</p>
              <p>Loài được nuôi nhiều nhất</p>
            </div>
            <div style={{
              backgroundColor: '#f8f9fa',
              padding: '25px',
              borderRadius: 'var(--border-radius)',
              boxShadow: '0 2px 8px var(--shadow-light)',
              textAlign: 'center'
            }}>
              <h3>Báo cáo mới</h3>
              <p style={{ fontSize: '1.2em', fontWeight: 'bold', color: 'var(--text-dark)' }}>25</p>
              <p>Báo cáo chờ duyệt</p>
            </div>
          </div>
        </div>
      </div>
    // </div>
  );
}

export default Dashboard;
